#include <stdio.h>
#include <stdlib.h>
#include <string.h>

typedef struct Student {
    char name[101];
    int age;
} Student;

Student* createStudent(const char* name, int age) {
    Student* s = (Student*)malloc(sizeof(Student));
    strcpy(s->name, name);
    s->age = age;
    return s;
}

void displayStudent(const Student* s) {
    printf("%s\n%d\n", s->name, s->age);
}

int main() {
    char name[101];
    int age;
    // Read name (may contain spaces)
    if (!fgets(name, sizeof(name), stdin)) return 0;
    name[strcspn(name, "\n")] = '\0';
    if (scanf("%d", &age) != 1) return 0;
    // Single test case loop (T = 1)
    Student* stu = createStudent(name, age);
    displayStudent(stu);
    free(stu);
    return 0;
}

